export function getDevotionalById(id: string): Devotional | undefined {
  return devotionals.find(d => d.id === id);
}

export function getDevotionalsByCategory(category: string): Devotional[] {
  return devotionals.filter(d => d.category === category);
}

export function getDevotionalOfTheDay(): Devotional {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 0);
  const diff = now.getTime() - start.getTime();
  const oneDay = 1000 * 60 * 60 * 24;
  const dayOfYear = Math.floor(diff / oneDay);
  
  return devotionals[dayOfYear % devotionals.length];
}
